-- ── Node-RED ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Node-RED is a free, open-source flow-based programming tool that lets developers wire together hardware devices, APIs, and online services using a browser-based visual editor.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Open source project (OpenJS Foundation)$q$, company_size),
  headquarters = COALESCE($q$Open source (no HQ)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Node-RED Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Node-RED review 2026: what it is, key flow-based programming features, pricing (it is free), and the best alternatives for IoT and automation.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Node-RED is an open-source, flow-based programming tool originally created by Nick O'Leary and Dave Conway-Jones at IBM's Emerging Technology Services team. It started as a weekend prototype in January 2013, was open-sourced on GitHub in September 2013, and grew rapidly in popularity after being bundled with the Raspberry Pi in 2015, which introduced it to a huge hobbyist and IoT developer audience. In October 2016 it became one of the founding projects of the JS Foundation, and in 2019 that body merged with the Node.js Foundation to become the OpenJS Foundation, which has governed Node-RED ever since as a vendor-neutral open-source project. Node-RED provides a browser-based visual flow editor in which users wire together 'nodes' representing hardware devices, APIs, databases, and online services to build event-driven applications with minimal hand-written code. Its runtime is built on Node.js, giving it a lightweight, event-driven, non-blocking execution model that runs comfortably on low-cost edge hardware such as the Raspberry Pi as well as in cloud and enterprise environments. The palette of built-in nodes can be extended through a community library of more than 4,000-5,000 shared nodes covering protocols like MQTT, HTTP, Modbus, and integrations with cloud platforms (AWS, Azure, IBM Cloud), databases, and messaging systems. This extensibility, combined with the visual programming model, makes Node-RED especially popular for Industrial IoT (IIoT) integration, home automation, rapid API prototyping, and connecting disparate systems without writing large amounts of glue code. Because it is entirely open source (Apache 2.0 licensed) and community-governed under the OpenJS Foundation, there is no vendor, no company headquarters, and no paid tier for the core software itself; users self-host it on their own infrastructure or a Raspberry Pi, though commercial companies such as FlowFuse have built managed hosting and enterprise tooling on top of the open-source core. Node-RED's main competitors and adjacent tools include Zapier and Make (cloud-only, less code-adjacent automation), Apache NiFi (enterprise dataflow), Home Assistant's automation editor, and n8n (a more modern, similarly open-source flow-based automation tool). Target users range from hobbyists automating a home to industrial engineers building IIoT gateways and enterprise developers prototyping event-driven microservice glue code.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b0f2485e-46a1-44ad-84ac-a606befaef5f';

