-- ── NodeBB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$NodeBB is a modern, real-time discussion forum platform built on Node.js, offered as both free self-hosted open-source software and a fully managed hosted service.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted) or $20/month (hosted Starter plan)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Toronto, Ontario, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$NodeBB Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$NodeBB review 2026: real-time forum features, hosted and self-hosted pricing plans, pros and cons, and top community platform alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$NodeBB is a real-time, Node.js-based discussion forum platform created in 2013 by a small team of developers, including Julian Lam, who wanted a modern alternative to older PHP-based forum software like phpBB and vBulletin. The company behind it, NodeBB Inc., is headquartered in Toronto, Ontario, Canada, and remains a small, privately held team (roughly 1-10 employees on record). NodeBB's core technical differentiator is that it uses WebSockets for real-time updates, so new posts, notifications, and chat messages appear instantly without page reloads, and it stores data in NoSQL backends such as Redis, MongoDB, or PostgreSQL rather than a traditional relational schema. The platform ships with built-in real-time chat, granular category and privilege-based permissions, an extensible plugin and theme ecosystem, single sign-on options, gamification (badges, reputation), and native mobile-responsive design. NodeBB is dual-licensed: the core software is open source under the GPLv3 license and can be downloaded and self-hosted for free from GitHub, which makes it popular with developers and organizations that want full control over their community infrastructure. For teams that don't want to manage servers, NodeBB Inc. also sells a fully managed hosted service with tiered plans based on monthly pageviews and storage: Starter ($20/month, 50,000 pageviews), Hamlet ($100/month, 500,000 pageviews), Village ($250/month, 2,000,000 pageviews, its most popular tier), and City ($750/month, 10,000,000 pageviews), plus a custom-priced Enterprise tier with white-glove migration, SSO, and custom development. All hosted plans include unlimited staff accounts, automated backups, SSL, custom plugins, and custom domains, with a 14-day free trial. NodeBB also offers discounted or free hosting for qualifying non-profit and open-source projects. Typical customers include online communities, SaaS companies building customer/support forums, gaming and media communities, and open-source projects needing a discussion hub; notable adopters have included organizations in the DigitalOcean partner ecosystem. Its main competitors are Discourse (its closest real-time, modern-forum rival), phpBB and vBulletin (legacy self-hosted forums), Discord and Circle (community/chat-first alternatives), and Vanilla Forums. NodeBB is generally chosen over these when organizations want a fast, real-time, SEO-friendly, and highly customizable forum with the option to self-host at zero licensing cost.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8cded24f-f6e3-445f-86fb-dc2b2871d6b2';

