-- ── Noloco ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Noloco is a no-code platform for building internal tools, client portals, and business apps directly on top of data sources like Airtable, HubSpot, and SQL databases.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $99/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Dublin, Ireland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Noloco Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Noloco review 2026: no-code app builder features, pricing plans, pros and cons, and the best alternatives for building internal tools and client portals.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Noloco is a no-code application development platform founded in 2021 and headquartered in Dublin, Ireland. It lets non-technical teams build internal tools, CRMs, client portals, and team intranets directly on top of existing data sources such as Airtable, HubSpot, SmartSuite, Stripe, and SQL databases (via native integrations on higher tiers), without writing custom backend code. The company has raised roughly $5.4 million in seed and pre-seed funding from investors including Better Angle, Unpopular Ventures, and Anamcara Capital, and operates as a small, lean team (commonly reported as under 10-15 employees). Noloco's core positioning is as an 'operating system' for no-code businesses: users connect a data source, then use a visual builder to create record-level permissions, custom workflows, dashboards, and client-facing portals with white-label branding, targeting agencies and small businesses that need to deliver client tools quickly without hiring developers. Its built-in AI assistant, called Nola, helps users generate app structure, workflows, and content directly inside the builder. Pricing follows a classic no-code SaaS structure: a genuinely free plan (3 team seats, 7 client seats, 2,000 rows, unlimited apps, 100 workflow runs) for testing and small projects; a Pro plan (roughly $99-149/month depending on annual or monthly billing) adding custom domains, record/field-level permissions, custom code support, and Airtable/SmartSuite/Stripe integrations; a Business plan (roughly $213-319/month) adding HubSpot and SQL database integrations, more seats and workflow runs, and unlimited user roles; and a custom-priced Enterprise plan with SSO, two-factor authentication, a dedicated support manager, and full white-labeling. Non-profits receive a 50 percent discount on paid plans, and all paid tiers include a 14-day free trial. Noloco's target audience spans no-code agencies building client deliverables, internal operations teams replacing spreadsheets with structured apps, and startups needing a fast internal admin panel or customer portal without engineering resources. Its closest competitors are other no-code app builders and internal-tool platforms such as Softr, Stacker, Glide, Bubble, and Retool, with Noloco generally differentiated by its strong native Airtable/HubSpot integration, client-portal focus, and competitive pricing for agencies managing multiple client apps.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f9bc7649-dc5b-4824-b0b4-1f220d996bc3';

