-- ── Nominatim ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Nominatim is the free, open-source geocoding and reverse-geocoding search engine that powers address lookups on the official OpenStreetMap website, built on OpenStreetMap data.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Open source project (OpenStreetMap Foundation and volunteer contributors)$q$, company_size),
  headquarters = COALESCE($q$Open source (no HQ)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nominatim Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nominatim review 2026: how this open-source OpenStreetMap geocoding tool works, usage policy, self-hosting, and the best geocoding API alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nominatim (from the Latin 'by name') is the open-source geocoding and reverse-geocoding search engine that powers the address search box on the official openstreetmap.org website and many other map applications built on OpenStreetMap data. It was originally created by Brian Quinion and has since been developed and maintained as a community project under the umbrella of the OpenStreetMap Foundation (OSMF), which also funds and operates the public Nominatim instance used by the main OSM site. Technically, Nominatim is built around osm2pgsql, a PostgreSQL-based OSM data import utility, using an alternative 'gazetteer' output mode, with the indexing and search layers implemented in a combination of C, PL/pgSQL, and Python; queries are served against a PostGIS-backed PostgreSQL database. The public instance at nominatim.openstreetmap.org handles an extremely high query volume, reportedly serving on the order of tens of millions of queries per day, and is governed by a strict usage policy (the 'Nominatim Usage Policy' published by OSMF Operations) that limits automated/bulk use, requires attribution, and caps request rates for the free public API to protect shared infrastructure. Because it is entirely open source (available on GitHub under the osm-search organization) and free of charge, Nominatim is widely self-hosted by companies, researchers, and government/GIS teams that need higher query volumes, guaranteed uptime, or offline/on-premises geocoding without relying on the shared public endpoint; self-hosting requires importing a full or regional OpenStreetMap data extract into a PostgreSQL/PostGIS database, which is resource-intensive (full planet imports typically require substantial RAM and storage) but gives complete control and no per-query cost. There is no company behind Nominatim, no headquarters, no employees, and no commercial pricing tiers for the core software itself; it is maintained by open-source volunteer contributors and OSMF-funded infrastructure. Because the free public API has strict rate limits and usage restrictions, a commercial ecosystem of hosted Nominatim providers has emerged, including Geoapify, LocationIQ, and MapTiler, which offer managed, rate-limit-free Nominatim-compatible geocoding as a paid API service. Nominatim's primary alternatives are Google Maps Geocoding API, Mapbox Geocoding, HERE Geocoding, and the open-source Photon and Pelias projects; Nominatim is generally chosen by developers and organizations who want a genuinely free, open-data-based geocoder with no vendor lock-in, especially when paired with other OpenStreetMap-based tooling.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '48148d92-39dd-4402-8645-08c7801fdbd5';

